INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: IIT Gandhinagar is located in Gandhinagar, Gujarat.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: 24/7 WiFi throughout campus. Every hostel room has LAN wire.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: ACs work during summer nights in hostels.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: All classrooms have central AC.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: A pantry with refrigerator, electric stove, oven, and water dispenser is available on every floor in hostels.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: You can go out of campus whenever you want - no curfew.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: Inter-hostel mobility - boys and girls allowed to visit opposite gender hostels with consent.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: Classroom booking available via Google Calendar during exam times.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Gandhinagar', 'overview', 'Overview > Facts: Large library (9 AM - 12 AM) and mini library (24/7) with website to check book availability.');
